// ================================================
// REAL-TIME SIGNAL AGENT v2.6 — Batch snapshots fix for timeout — Tickers from upstream node, not inline API call — Fix #18 static data keys — Fix #7 getSnapshot, Fix #3 fallback alert — Threshold Alignment Fix — HYBRID FEEDER + DEBUG LOGGING
// Scans 105 tickers from Google Sheet
// ================================================

// GOOGLE_SHEET_ID removed — tickers now loaded via upstream Google Sheets node

// ================== CONFIG ==================
const MOMENTUM_THRESHOLD = 0.7;  // v2.2: lowered from 1.0 to match Broad Scanner
const PROFILE_IMBALANCE = 1.8;        // Kioseff Market Structure
const VOLUME_MIN = 0.3;
const MIN_RR = 2.0;

// v2.6 — Batch snapshots fix for timeout — Tickers from upstream node, not inline API call: Use workflow static data for API keys (Fix #18)
const _creds = $getWorkflowStaticData('global');
const ALPACA_KEY = _creds._alpaca_key || 'REDACTED_ALPACA_KEY_ID';
const ALPACA_SECRET = _creds._alpaca_secret || 'REDACTED_ALPACA_SECRET';


console.log("🚀 Hybrid Agent started - Scanning 105 tickers");

// ================== LOAD TICKERS FROM UPSTREAM GOOGLE SHEETS NODE ==================
// v2.6 — Batch snapshots fix for timeout: Tickers now come from the "Load Tickers" Google Sheets node (pre-stage)
// This fixes the httpRequestWithAuthentication error in Code nodes.
const FALLBACK_TICKERS = ["TSLA","NVDA","AMD","MSFT","GILD","SPY","QQQ","AAPL","GOOGL","AMZN","META","SMCI","NBIS","CRWV"];
let tickers = [];

try {
  const inputItems = $input.all();
  tickers = inputItems
    .map(item => {
      const row = item.json;
      return row.Ticker || row.ticker || row.COST || Object.values(row).find(v => typeof v === 'string' && v.length <= 6 && /^[A-Z]+$/.test(v));
    })
    .filter(t => t && typeof t === 'string' && t.length >= 1 && t.length <= 6 && /^[A-Z]+$/.test(t.toUpperCase()))
    .map(t => t.toUpperCase());

  if (tickers.length === 0) {
    throw new Error('Sheet returned 0 valid tickers');
  }

  console.log('Sheet loaded: ' + tickers.length + ' tickers from upstream node');
} catch (e) {
  console.log('Sheet parse failed: ' + e.message + ' — using ' + FALLBACK_TICKERS.length + '-ticker fallback');
  tickers = FALLBACK_TICKERS;

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/botREDACTED_TELEGRAM_BOT_TOKEN/sendMessage',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: REDACTED_CHAT_ID,
        text: '[RT AGENT] Sheet parse failed — ' + FALLBACK_TICKERS.length + '-ticker fallback. Error: ' + e.message
      }),
      json: true
    });
  } catch (tgErr) { /* silent */ }
}

// ================== MAIN LOOP ==================
const vixData = await getSnapshot("I:VIX");
const vix = vixData?.price || 25.0;
console.log(`📊 VIX = ${vix.toFixed(1)}`);

let signalsFound = 0;

for (const ticker of tickers) {
    const data = await getSnapshot(ticker);
    if (!data || !data.price) {
        console.log(`⚠️ ${ticker} — No data`);
        continue;
    }

    const signal = evaluateTicker(ticker, data, vix);

    if (signal) {
        signalsFound++;
        console.log(`🔥 SIGNAL FOUND → ${ticker} ${signal.signal} | ${signal.reason} | Conf ${signal.confidence}% | R:R ${signal.rr}`);

        // Push to VC Gate + AI Super Score pipeline
        await this.helpers.httpRequest({
            method: 'POST',
            url: 'https://tradenextgen.app.n8n.cloud/webhook/tradingview-signal',
            headers: { 'Content-Type': 'application/json' },
            body: {
                ticker: ticker,
                price: signal.price,
                execution: signal.signal,
                signal: signal.signal === "SELL" ? "BEARISH" : "BULLISH",
                bias_score: signal.confidence,
                regime: "TRENDING",
                adx: "N/A",
                rsi: "N/A",
                macd_hist: "N/A",
                atr: signal.atr_est,
                volume_ratio: signal.vol_ratio,
                vix: vix.toFixed(1),
                timeframe: "5",
                alert_type: "REALTIME_AGENT_HYBRID",
                comment: `HYBRID AGENT v2.1 + Kioseff Structure: ${signal.reason} | R:R=${signal.rr}`,
                momentum_engine: "true",
                momentum_type: "realtime_agent"
            }
        });
    } else {
        // Debug why it was skipped
        const changePct = (data.price - data.prev_close) / data.prev_close * 100;
        const volRatio = data.volume / data.avg_volume;
        console.log(`⏭️ ${ticker} skipped | change ${changePct.toFixed(2)}% | vol ${volRatio.toFixed(2)}x | (no threshold met)`);
    }
}

console.log(`✅ Scan complete — Signals found: ${signalsFound} | Tickers scanned: ${tickers.length}`);

return { signalsFound, tickersScanned: tickers.length };

// ================== HELPERS ==================
// v2.6: Batch snapshot fetcher — pre-loads all tickers in 1-2 API calls
// (replaces 102 individual calls that caused 60s timeouts)
var _batchSnapshots = null;
async function loadBatchSnapshots(tickerList) {
  if (_batchSnapshots) return; // already loaded
  _batchSnapshots = {};
  const batchSize = 100;
  for (let b = 0; b < tickerList.length; b += batchSize) {
    const batch = tickerList.slice(b, b + batchSize)
      .filter(t => /^[A-Z]{1,6}$/.test(t)); // strip invalid tickers like OIL
    if (!batch.length) continue;
    try {
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://data.alpaca.markets/v2/stocks/snapshots?symbols=' + batch.join(',') + '&feed=iex',
        headers: { 'APCA-API-KEY-ID': ALPACA_KEY, 'APCA-API-SECRET-KEY': ALPACA_SECRET },
        json: true
      });
      Object.assign(_batchSnapshots, resp || {});
    } catch (e) {
      console.log('[BATCH] Snapshot fetch failed for batch: ' + e.message);
    }
  }
  console.log('[BATCH] Loaded snapshots for ' + Object.keys(_batchSnapshots).length + ' tickers');
}

async function getSnapshot(ticker) {
  if (!_batchSnapshots) return null; // loadBatchSnapshots must run first
  const snap = _batchSnapshots[ticker];
  if (!snap || !snap.latestTrade || !snap.dailyBar || !snap.prevDailyBar) return null;
  return {
    price:      snap.latestTrade.p,
    prev_close: snap.prevDailyBar.c,
    volume:     snap.dailyBar.v,
    avg_volume: snap.prevDailyBar.v,
    day_high:   snap.dailyBar.h,
    day_low:    snap.dailyBar.l
  };
}

function evaluateTicker(ticker, data, vix) {
    const changePct = (data.price - data.prev_close) / data.prev_close * 100;
    const volRatio = data.volume / data.avg_volume;

    let signal = null;
    let reason = "";

    if (changePct <= -MOMENTUM_THRESHOLD && volRatio >= VOLUME_MIN) {
        signal = "SELL";
        reason = `MOMENTUM SHORT: ${changePct.toFixed(1)}% | vol ${volRatio.toFixed(1)}x`;
    } else if (changePct >= MOMENTUM_THRESHOLD && volRatio >= VOLUME_MIN && vix < 30) {
        signal = "BUY";
        reason = `MOMENTUM LONG: ${changePct.toFixed(1)}% | vol ${volRatio.toFixed(1)}x`;
    } else if (volRatio >= PROFILE_IMBALANCE && changePct < -0.8) {
        signal = "SELL";
        reason = `MARKET STRUCTURE BREAK (Kioseff) - imbalance ${volRatio.toFixed(1)}x`;
    }

    if (!signal) return null;

    const atrEst = (data.day_high - data.day_low) || (data.price * 0.01);
    const slDist = atrEst * 1.5;
    const tpDist = atrEst * 3.0;
    if (tpDist / slDist < MIN_RR) return null;

    return {
        signal,
        price: Number(data.price.toFixed(2)),
        confidence: Math.round(Math.abs(changePct) * 25 + volRatio * 15),
        reason,
        vol_ratio: Number(volRatio.toFixed(2)),
        atr_est: Number(atrEst.toFixed(2)),
        rr: Number((tpDist / slDist).toFixed(1))
    };
}
